  -- Открыть сплит и терминал
  vim.cmd("botright split | resize 15 | terminal")

  -- Получить ID буфера терминала
  local term_buf = vim.api.nvim_get_current_buf()
  local term_chan = vim.b.terminal_job_id

  -- Отправить команду в терминал
  vim.fn.chansend(term_chan, "./staros-rebuild --configure-only\n")

  -- Установить автокоманду, которая сработает после завершения
  vim.api.nvim_create_autocmd("TermClose", {
    buffer = term_buf,
    once = true,
    callback = function()
      vim.cmd("bd!")                   -- Закрыть терминал-буфер
      vim.lsp.stop_client(vim.lsp.get_active_clients()) -- Остановить LSP
      vim.cmd("edit")                 -- Перезагрузить текущий буфер
      vim.cmd("LspStart")             -- Запустить LSP заново
      vim.notify("Rebuild complete and LSP restarted", vim.log.levels.INFO)
    end,
  })
end
